import{_ as s,o as e,c as n,ag as o}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"第6章 Python SDK 设计","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/06-python-sdk.md","filePath":"chapters/06-python-sdk.md"}'),t={name:"chapters/06-python-sdk.md"};function i(d,a,p,c,l,r){return e(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="第6章-python-sdk-设计" tabindex="-1">第6章 Python SDK 设计 <a class="header-anchor" href="#第6章-python-sdk-设计" aria-label="Permalink to &quot;第6章 Python SDK 设计&quot;">​</a></h1><blockquote><p>&quot;好的 API 应该像一篇优美的散文——读起来自然流畅，写起来心中有数。&quot; —— Joshua Bloch</p></blockquote><h2 id="_6-1-包结构总览" tabindex="-1">6.1 包结构总览 <a class="header-anchor" href="#_6-1-包结构总览" aria-label="Permalink to &quot;6.1 包结构总览&quot;">​</a></h2><p>OpenSandbox 的 Python SDK 位于 <code>sdks/sandbox/python/src/opensandbox/</code>，是用户与沙箱系统交互的主要入口。整个包的目录结构经过精心设计，职责划分清晰：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensandbox/</span></span>
<span class="line"><span>├── adapters/        # HTTP 适配层（基于 httpx）</span></span>
<span class="line"><span>├── api/             # 底层 API 调用封装</span></span>
<span class="line"><span>├── config/          # 连接配置管理</span></span>
<span class="line"><span>├── exceptions/      # 自定义异常体系</span></span>
<span class="line"><span>├── models/          # 数据模型定义</span></span>
<span class="line"><span>├── services/        # 高层服务抽象（Files, Commands, Metrics 等）</span></span>
<span class="line"><span>├── sync/            # 同步 API 镜像实现</span></span>
<span class="line"><span>│   ├── adapters/</span></span>
<span class="line"><span>│   ├── services/</span></span>
<span class="line"><span>│   ├── manager.py</span></span>
<span class="line"><span>│   └── sandbox.py</span></span>
<span class="line"><span>├── constants.py     # 常量定义</span></span>
<span class="line"><span>├── manager.py       # SandboxManager 管理器</span></span>
<span class="line"><span>├── sandbox.py       # Sandbox 核心类</span></span>
<span class="line"><span>└── py.typed         # PEP 561 类型标记</span></span></code></pre></div><p>为什么采用这样的分层结构？核心原因在于<strong>关注点分离</strong>。<code>adapters/</code> 层将 HTTP 传输细节（httpx 异步客户端、连接池、超时控制）与业务逻辑完全隔离，未来若要替换为其他 HTTP 库，只需修改适配层。<code>services/</code> 层则通过 Protocol 协议定义了六大服务接口：Commands、Filesystem、Health、Metrics、Egress 和 Sandboxes，让上层代码面向接口编程而非绑定具体实现。</p><p><code>exceptions/</code> 目录定义了 SDK 自己的异常层次结构，将底层 HTTP 错误（网络超时、连接拒绝）和业务错误（沙箱不存在、状态冲突）统一包装为 <code>SandboxException</code> 及其子类。这样做的好处是用户只需捕获一种异常类型，就能处理所有 SDK 相关的错误情况。<code>config/</code> 目录管理连接配置——lifecycle server 的地址、认证令牌、超时参数等，支持从环境变量或配置对象中读取，为不同部署环境（本地开发、测试、生产）提供灵活的配置方式。<code>models/</code> 目录则包含所有请求和响应的数据模型定义，利用 Python 类型注解和 Pydantic 风格的验证确保数据的完整性和类型安全。</p><p><code>py.typed</code> 文件虽然内容为空，却意义重大——它是 PEP 561 规定的类型标记文件，告诉 mypy 等类型检查工具&quot;这个包提供了内联的类型注解&quot;。对于 SDK 库来说，良好的类型支持直接影响开发者在 IDE 中的自动补全和错误提示体验。</p><h2 id="_6-2-sandbox-核心类" tabindex="-1">6.2 Sandbox 核心类 <a class="header-anchor" href="#_6-2-sandbox-核心类" aria-label="Permalink to &quot;6.2 Sandbox 核心类&quot;">​</a></h2><p><code>sandbox.py</code> 是整个 SDK 的灵魂所在。Sandbox 类采用<strong>静态工厂方法</strong>模式，提供三种实例化路径：</p><ul><li><code>Sandbox.create()</code> — 创建全新沙箱，传入镜像、环境变量、网络策略、资源限制等参数</li><li><code>Sandbox.connect()</code> — 通过 sandbox_id 连接到已有的运行中沙箱</li><li><code>Sandbox.resume()</code> — 恢复一个已暂停的沙箱</li></ul><p>为什么不用普通构造函数？因为沙箱的创建涉及异步网络调用——需要向 lifecycle server 发送 POST 请求，轮询等待容器就绪。Python 的 <code>__init__</code> 方法不支持 <code>await</code>，而静态工厂方法 <code>create()</code> 作为 <code>async</code> 函数可以优雅地处理这一流程。</p><p>Sandbox 实例通过<strong>属性代理</strong>提供服务访问：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox.files      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → Filesystem 服务：文件的增删改查、上传下载</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox.commands    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → Commands 服务：命令执行与后台任务</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox.metrics     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → Metrics 服务：CPU、内存等资源监控</span></span></code></pre></div><p>这种设计让用户代码读起来像自然语言：<code>sandbox.files.write(&quot;/tmp/data.txt&quot;, content)</code> 就是&quot;在沙箱的文件系统中写入一个文件&quot;。</p><h2 id="_6-3-生命周期管理" tabindex="-1">6.3 生命周期管理 <a class="header-anchor" href="#_6-3-生命周期管理" aria-label="Permalink to &quot;6.3 生命周期管理&quot;">​</a></h2><p>Sandbox 类提供了完整的生命周期操作方法：</p><ul><li><strong>暂停与终止</strong>：<code>pause()</code> 冻结沙箱状态，<code>kill()</code> 永久终止远程实例（不可逆），<code>close()</code> 释放本地连接资源</li><li><strong>续期</strong>：<code>renew(timeout)</code> 延长沙箱过期时间，底层使用 UTC 时区感知的 datetime 计算</li><li><strong>状态查询</strong>：<code>get_info()</code> 获取完整状态信息，<code>get_metrics()</code> 查看资源用量，<code>is_healthy()</code> 执行健康检查，<code>check_ready()</code> 以轮询方式等待沙箱就绪</li></ul><p>值得注意的是 <code>create()</code> 方法内部的<strong>自动清理机制</strong>：如果沙箱创建过程中出现异常（例如超时或镜像拉取失败），SDK 会自动尝试 kill 已创建的远程实例，避免留下僵尸容器。这种防御性设计体现了对生产环境稳定性的重视。</p><h2 id="_6-4-网络策略控制" tabindex="-1">6.4 网络策略控制 <a class="header-anchor" href="#_6-4-网络策略控制" aria-label="Permalink to &quot;6.4 网络策略控制&quot;">​</a></h2><p>网络相关操作通过两个方法暴露：</p><ul><li><code>get_egress_policy()</code> — 查询当前出口流量策略</li><li><code>patch_egress_rules()</code> — 增量更新出口规则</li></ul><p>结合 <code>get_endpoint()</code> 和 <code>get_endpoint_url()</code>，用户可以获取沙箱对外暴露的服务地址。这种设计将网络策略管理与沙箱访问地址解析统一在 Sandbox 对象上，避免了用户需要单独管理网络配置的复杂性。</p><h2 id="_6-5-异步上下文管理器" tabindex="-1">6.5 异步上下文管理器 <a class="header-anchor" href="#_6-5-异步上下文管理器" aria-label="Permalink to &quot;6.5 异步上下文管理器&quot;">​</a></h2><p>SDK 支持 Python 的 <code>async with</code> 语法，实现自动资源清理：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">async</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> with</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Sandbox.create(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">image</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;python:3.11&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sandbox:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sandbox.commands.run(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;echo hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 退出 with 块时自动调用 close() 释放连接资源</span></span></code></pre></div><p>这里有一个微妙的设计点：<code>await Sandbox.create(...)</code> 返回的 Sandbox 对象实现了 <code>__aenter__</code> 和 <code>__aexit__</code> 协议。<code>__aexit__</code> 中调用的是 <code>close()</code> 而非 <code>kill()</code>——这意味着退出上下文仅释放本地连接，沙箱实例依然存活直到超时过期。如果用户需要立即销毁沙箱，应在 with 块内显式调用 <code>kill()</code>。</p><h2 id="_6-6-sandboxmanager-批量管理" tabindex="-1">6.6 SandboxManager：批量管理 <a class="header-anchor" href="#_6-6-sandboxmanager-批量管理" aria-label="Permalink to &quot;6.6 SandboxManager：批量管理&quot;">​</a></h2><p>当需要管理多个沙箱时，SandboxManager 提供了<strong>行政层面的操作</strong>：</p><ul><li><code>list_sandbox_infos(filter)</code> — 列出沙箱，支持过滤条件</li><li><code>get_sandbox_info(sandbox_id)</code> — 查询特定沙箱详情</li><li><code>kill_sandbox()</code> / <code>pause_sandbox()</code> / <code>resume_sandbox()</code> — 批量生命周期操作</li><li><code>renew_sandbox()</code> — 为指定沙箱续期</li></ul><p>SandboxManager 同样采用工厂方法 <code>create()</code> 实例化，并支持 async 上下文管理器。它与 Sandbox 类的职责边界非常明确：Sandbox 负责&quot;单个沙箱的一切操作&quot;，SandboxManager 负责&quot;跨沙箱的发现与管理&quot;。</p><h2 id="_6-7-双-api-模式-异步与同步" tabindex="-1">6.7 双 API 模式：异步与同步 <a class="header-anchor" href="#_6-7-双-api-模式-异步与同步" aria-label="Permalink to &quot;6.7 双 API 模式：异步与同步&quot;">​</a></h2><p><code>sync/</code> 目录下完整镜像了异步 API 的同步版本：</p><table tabindex="0"><thead><tr><th>异步 API</th><th>同步 API</th></tr></thead><tbody><tr><td><code>Sandbox</code></td><td><code>SandboxSync</code></td></tr><tr><td><code>SandboxManager</code></td><td><code>SandboxManagerSync</code></td></tr></tbody></table><p>同步版本包装了异步实现，内部通过事件循环桥接。这种设计让 SDK 同时服务于两类用户：追求高并发的异步应用，以及脚本化场景下更简单的同步调用。<code>sync/</code> 目录下同样包含对应的 <code>adapters/</code> 和 <code>services/</code>，保证同步版本拥有完整的功能覆盖。</p><h2 id="_6-8-扩展-sdk-生态" tabindex="-1">6.8 扩展 SDK 生态 <a class="header-anchor" href="#_6-8-扩展-sdk-生态" aria-label="Permalink to &quot;6.8 扩展 SDK 生态&quot;">​</a></h2><p>在核心 Sandbox SDK 之上，OpenSandbox 还提供了两个专用 SDK：</p><p><strong>Code Interpreter SDK</strong>（<code>sdks/code-interpreter/python/</code>）封装了有状态的多语言代码执行能力，通过 Jupyter kernel 实现 Python、Java、Go、TypeScript 等语言的交互式执行，支持会话上下文保持。</p><p><strong>MCP SDK</strong>（<code>sdks/mcp/sandbox/python/</code>）实现了 Model Context Protocol 集成，让 AI 模型能够通过标准化协议直接调用沙箱操作——创建沙箱、执行代码、读写文件等，为 AI Agent 场景提供了开箱即用的工具集。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>Python SDK 的设计哲学可以归纳为三个关键词：<strong>分层隔离</strong>（adapters → services → Sandbox）、<strong>双模并行</strong>（async + sync）、<strong>接口优先</strong>（Protocol 协议定义服务契约）。静态工厂方法解决了异步构造的难题，上下文管理器确保了资源安全，而 SandboxManager 则为规模化管理提供了便捷入口。这套设计在保持 API 简洁性的同时，为不同使用场景提供了足够的灵活性。</p>`,41)])])}const b=s(t,[["render",i]]);export{k as __pageData,b as default};
